    bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 0, 0))
    floor = bpy.context.active_object
    floor.scale = (10, 10, 0.1)
    floor.name = "Floor"
    bpy.ops.object.shade_smooth()

    # 2. Walls
    bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 0, 0))
    wall = bpy.context.active_object
    wall.scale = (8, 4, 1)
    wall.location.y = 2
    wall.name = "Walls"
    bpy.ops.object.shade_smooth()

